def detect_smurfing(transactions):
    if not transactions:
        return False

    # Group transactions by user
    user_data = {}
    for txn in transactions:
        uid = txn['user_id']
        amount = txn['amount']
        if uid not in user_data:
            user_data[uid] = []
        user_data[uid].append(amount)

    # Check for smurfing pattern: multiple small transfers followed by a large one
    for u_amounts in user_data.values():
        if len(u_amounts) > 1:
            # Check if there are multiple small transactions (under 100) and at least one large (over 100)
            small_count = sum(1 for a in u_amounts if a < 100)
            large_count = sum(1 for a in u_amounts if a > 100)
            if small_count > 1 and large_count > 0:
                return True

    return False
