        user_txns[t['user_id']].append(t['amount'])

    threshold = 1000
    reporting_limit = int(threshold * 0.9)

    for amounts in user_txns.values():
        if len(amounts) <= 1:
            continue
        if len(amounts) < 3:
            continue
        if sum(amounts) > threshold:
            continue
        if sum(amounts) < reporting_limit and len(amounts) > 3:
            return True

